package main

import (
	"math"
)

func solve(nums []int64) int64 {
	// Function to check if a number is a prime
	isPrime := func(n int) bool {
		if n <= 1 {
			return false
		}
		if n == 2 {
			return true
		}
		if n%2 == 0 {
			return false
		}
		for i := 3; i <= int(math.Sqrt(float64(n))); i += 2 {
			if n%i == 0 {
				return false
			}
		}
		return true
	}

	var sumA, sumB int64
	for i, num := range nums {
		if isPrime(i) {
			sumA += num
		} else {
			sumB += num
		}
	}
	return int64(math.Abs(float64(sumA - sumB)))
}
